    'Core': {'System.Text.Json': '9.0.0'},
    'Web': {'Microsoft.AspNetCore.OpenApi': '8.0.24', 'OpenTelemetry.Extensions.Hosting': '1.15.0'},
    'Tests': {'Microsoft.NET.Test.Sdk': '17.12.0', 'xunit': '2.9.3', 'xunit.runner.visualstudio': '2.8.2'}
}
all_match = True
for proj in after['projects']:
    name = proj['path'].split('/')[-2]
    for fw in proj['frameworks']:
        for pkg in fw['topLevelPackages']:
            bv = baseline.get(name, {}).get(pkg['id'])
            if bv != pkg['resolvedVersion']:
                print(f'MISMATCH: {name}/{pkg[\"id\"]}: baseline={bv} after={pkg[\"resolvedVersion\"]}')
                all_match = False
if all_match:
    print('All packages match baseline versions - conversion is version-neutral')
"

